from __future__ import annotations

import logging
import re
from typing import Any, Dict, Optional, Union

from fitz_ai.core.instrumentation import BenchmarkHook
from fitz_ai.llm.providers.base import ChatProvider, EmbeddingProvider, RerankProvider, VisionProvider

logger = logging.getLogger(__name__)

class TokenTrackingHook(BenchmarkHook):
    """
    A benchmark hook that tracks token usage from LLM calls for cost tracking purposes.

    This implementation extracts prompt_tokens and completion_tokens from provider responses
    when available, falling back to estimation using Tiktoken where native metrics aren't provided. 
    """

    def __init__(self) -> None:
        self._tiktoken_available = False
        try:
            import tiktoken  # noqa: F401
            self._tiktoken_available = True
        except ImportError:
            logger.debug("Tiktoken not available for token estimation")

    def on_call_start(
        self,
        layer: str,
        plugin_name: str,
        method: str,
        args: tuple,
        kwargs: dict,
    ) -> Any:
        # No pre-call setup needed - we track at call end
        return None

    def on_call_end(
        self,
        context: Any,
        result: Any,
        error: Exception | None,
    ) -> None:
        if error is not None or result is None:
            return

        # Extract token usage from known provider response formats
        try:
            self._extract_and_log_tokens(context, result)
        except Exception as e:
            logger.debug(f"Failed to extract tokens for call: {e}")

    def _extract_and_log_tokens(self, context: Any, result: Any) -> None:
        """Extract token usage from response and log it."""
        # Extract provider info from the context if available
        provider_info = self._get_provider_info(context)
        if not provider_info or "provider" not in provider_info:
            return

        try:
            tokens = self._extract_tokens_from_response(result, provider_info)
            if tokens is None and self._tiktoken_available:
                # Fall back to estimation using Tiktoken
                estimated_tokens = self._estimate_tokens(provider_info, result)
                if estimated_tokens:
                    tokens = estimated_tokens
            elif tokens is None:
                return  # No token data available or estimations failed

            # Log the tokens - in a real system this would go to metrics collection
            logger.debug(
                f"Token usage for {provider_info.get('provider')}/{provider_info.get('model', 'unknown')} - "
                f"prompt: {tokens.get('prompt_tokens', 0)}, completion: {tokens.get('completion_tokens', 0)}"
            )
        except Exception as e:
            logger.debug(f"Error extracting tokens from response: {e}")

    def _get_provider_info(self, context: Any) -> Optional[Dict[str, str]]:
        """Extract provider information from the instrumentation context."""
        # The context is a tuple of (layer, plugin_name, method) from InstrumentedProxy._wrap_method
        if hasattr(context, '__len__') and len(context) >= 3:
            layer = context[0] if isinstance(context[0], str) else None
            plugin_name = context[1] if isinstance(context[1], str) else None

            # Extract model information from the provider name or method calls if possible
            info: Dict[str, str] = {"provider": layer or "unknown"}

            if hasattr(self, '_model_from_context') and callable(getattr(self, '_model_from_context')):
                try:
                    model_info = self._model_from_context(context)
                    if model_info.get('model_name'):
                        info['model'] = model_info['model_name']
                except Exception as e:
                    logger.debug(f"Failed to extract model from context: {e}")

            return info
        elif hasattr(context, 'provider') and hasattr(context, 'model'):  # Directly passed provider data
            return {"provider": getattr(context, "provider"), "model": getattr(context, "model")}
        else:
            # Fallback to generic information from context
            if isinstance(context, dict) and 'layer' in context and 'plugin_name' in context:
                return {
                    "provider": context.get('layer', 'unknown'), 
                    "model": context.get('plugin_name', 'unknown')
                }
        return {"provider": "unknown", "model": "unknown"}

    def _extract_tokens_from_response(self, result: Any, provider_info: Dict[str, str]) -> Optional[Dict[str, int]]:
        """Extract token usage from response objects for different providers."""
        if not result or not isinstance(result, (str, dict)):
            return None

        provider = provider_info.get("provider", "").lower()

        # Handle OpenAI-style responses - check for metadata in response dicts
        if "openai" in provider and isinstance(result, dict):
            # Check for OpenAI usage fields in response structure
            usage = result.get('usage', {})
            if isinstance(usage, dict):
                tokens = {}
                if 'prompt_tokens' in usage:
                    tokens['prompt_tokens'] = usage['prompt_tokens']
                if 'completion_tokens' in usage:  
                    tokens['completion_tokens'] = usage['completion_tokens']
                if 'total_tokens' in usage:
                    tokens['total_tokens'] = usage['total_tokens']
                return tokens if tokens else None

        # Handle Anthropic-style responses - check for metadata fields
        elif "anthropic" in provider and isinstance(result, dict):
            # Anthropic may have response headers or structured data with token counts
            # This is a simplified check; real implementation would need to be more specific
            if 'usage' in result:
                usage = result['usage']
                if isinstance(usage, dict):
                    tokens = {}
                    if 'input_tokens' in usage:
                        tokens['prompt_tokens'] = usage['input_tokens']
                    if 'output_tokens' in usage:  
                        tokens['completion_tokens'] = usage['output_tokens']
                    return tokens if tokens else None

        # Handle Cohere-style responses - check for metadata fields
        elif "cohere" in provider and isinstance(result, dict):
            if 'meta' in result and isinstance(result['meta'], dict) and 'tokens' in result['meta']:
                tokens = result['meta']['tokens']
                if isinstance(tokens, dict):  
                    extracted_tokens = {}
                    if 'prompt_tokens' in tokens:
                        extracted_tokens['prompt_tokens'] = tokens['prompt_tokens']
                    if 'completion_tokens' in tokens:  
                        extracted_tokens['completion_tokens'] = tokens['completion_tokens']
                    return extracted_tokens if extracted_tokens else None

        # Handle Ollama-style responses - check for usage information or other metadata
        elif "ollama" in provider and isinstance(result, dict):
            if 'prompt_eval_count' in result or 'eval_count' in result:
                tokens = {}
                if 'prompt_eval_count' in result:  # Ollama uses prompt_eval_count for prompt tokens
                    tokens['prompt_tokens'] = result['prompt_eval_count']
                if 'eval_count' in result:  # Ollama uses eval_count for completion tokens (if available)
                    tokens['completion_tokens'] = result['eval_count']
                return tokens if tokens else None

        # Handle text-based responses - try to extract from string formats that might contain token info
        elif isinstance(result, str) and "tokens" in result.lower():
            # Try parsing common token count patterns (basic approach)
            pattern = r'(prompt|input)_tokens?[:\s]+(\d+)'
            match = re.search(pattern, result, re.IGNORECASE)
            if match:
                prompt_tokens = int(match.group(2))
                return {"prompt_tokens": prompt_tokens}

        # For other provider types or when no specific parsing is available, try to estimate using Tiktoken
        return None

    def _estimate_tokens(self, provider_info: Dict[str, str], result: Any) -> Optional[Dict[str, int]]:
        """Estimate tokens using Tiktoken if available."""
        try:
            import tiktoken
        except ImportError:
            logger.debug("Tiktoken not installed - cannot estimate tokens")
            return None

        # For text responses, we'll count tokens based on the result string content
        if isinstance(result, str):
            # Get model name from provider info for encoding selection
            model_name = provider_info.get("model", "gpt-4o")  # Default fallback

            try:
                # Select appropriate tokenizer (fallback to gpt-4o if unknown)
                enc = tiktoken.encoding_for_model(model_name) if 'gpt' in model_name else tiktoken.get_encoding('cl100k_base')
                token_count = len(enc.encode(result))
                return {"completion_tokens": token_count, "total_tokens": token_count}
            except Exception as e:
                logger.debug(f"Failed to estimate tokens with Tiktoken: {e}")
        elif isinstance(result, dict) and 'content' in result:
            # For structured responses that include content field
            content = str(result.get('content', ''))
            model_name = provider_info.get("model", "gpt-4o")
            try:
                enc = tiktoken.encoding_for_model(model_name) if 'gpt' in model_name else tiktoken.get_encoding('cl100k_base')
                token_count = len(enc.encode(content)) if content else 0
                return {"completion_tokens": token_count, "total_tokens": token_count}
            except Exception as e:
                logger.debug(f"Failed to estimate tokens with Tiktoken: {e}")
        elif hasattr(result, '__dict__') and hasattr(result, 'content'):  # Check for common fields in objects
            content = str(getattr(result, 'content', ''))
            model_name = provider_info.get("model", "gpt-4o")
            try:
                enc = tiktoken.encoding_for_model(model_name) if 'gpt' in model_name else tiktoken.get_encoding('cl100k_base')
                token_count = len(enc.encode(content)) if content else 0
                return {"completion_tokens": token_count, "total_tokens": token_count}
            except Exception as e:
                logger.debug(f"Failed to estimate tokens with Tiktoken: {e}")

        return None

